// var ilə hoisting nümunəsi
console.log(myVar); // undefined
var myVar = 'Salam';
console.log(myVar); // Salam
// Çıxış:
// undefined
// Salam

// let ilə hoisting nümunəsi
// console.log(myLet); // Səhv: Cannot access 'myLet' before initialization
let myLet = 'Salam';
console.log(myLet); // Salam
// const ilə hoisting nümunəsi
// console.log(myConst); // Səhv: Cannot access 'myConst' before initialization
const myConst = 'Dünya';
console.log(myConst); // Dünya
// Çıxış:
// Salam
// Dünya

// Funksiya elanı ilə hoisting nümunəsi
sayHello(); // Salam
function sayHello() {
    console.log('Salam');
}
// Çıxış:
// Salam

// Funksiya ifadəsi ilə hoisting nümunəsi
// sayHi(); // Səhv: sayHi is not a function
console.log(sayHi); // undefined
var sayHi = function() {
    console.log('Salam');
};
sayHi(); // Salam
// Çıxış:
// undefined
// Salam

// Arrow funksiyası ilə hoisting nümunəsi
// sayArrow(); // Səhv: sayArrow is not a function
console.log(sayArrow); // undefined
var sayArrow = () => console.log('Salam');
sayArrow(); // Salam
// Çıxış:
// undefined
// Salam

// Hoisting və scope nümunəsi
function testScope() {
    console.log(localVar); // undefined
    var localVar = 'Funksiya daxilində';
    console.log(localVar); // Funksiya daxilində
}
testScope();
// Çıxış:
// undefined
// Funksiya daxilində

// Səhvə yol açan nümunə
console.log(counter); // undefined
var counter = 5;
console.log(counter); // 5
// console.log(temp); // Səhv: Cannot access 'temp' before initialization
let temp = 10;
// Çıxış:
// undefined
// 5

