// Hoisting with var example
console.log(myVar); // undefined
var myVar = 'Hello';
console.log(myVar); // Hello
// Output:
// undefined
// Hello

// Hoisting with let example
// console.log(myLet); // Error: Cannot access 'myLet' before initialization
let myLet = 'Hello';
console.log(myLet); // Hello
// Hoisting with const example
// console.log(myConst); // Error: Cannot access 'myConst' before initialization
const myConst = 'World';
console.log(myConst); // World
// Output:
// Hello
// World

// Hoisting with function declaration example
sayHello(); // Hello
function sayHello() {
    console.log('Hello');
}
// Output:
// Hello

// Hoisting with function expression example
// sayHi(); // Error: sayHi is not a function
console.log(sayHi); // undefined
var sayHi = function() {
    console.log('Hello');
};
sayHi(); // Hello
// Output:
// undefined
// Hello

// Hoisting with arrow function example
// sayArrow(); // Error: sayArrow is not a function
console.log(sayArrow); // undefined
var sayArrow = () => console.log('Hello');
sayArrow(); // Hello
// Output:
// undefined
// Hello

// Hoisting and scope example
function testScope() {
    console.log(localVar); // undefined
    var localVar = 'Inside function';
    console.log(localVar); // Inside function
}
testScope();
// Output:
// undefined
// Inside function

// Error-prone example
console.log(counter); // undefined
var counter = 5;
console.log(counter); // 5
// console.log(temp); // Error: Cannot access 'temp' before initialization
let temp = 10;
// Output:
// undefined
// 5

